import{_ as a,o as d,c as e,ag as r}from"./chunks/framework.Vng7Hdlh.js";const p=JSON.parse('{"title":"22. スマレジ連携の全設定（完全ガイド）","description":"","frontmatter":{},"headers":[],"relativePath":"tenant/22-smaregi-full.md","filePath":"tenant/22-smaregi-full.md"}'),i={name:"tenant/22-smaregi-full.md"};function l(o,t,h,s,c,n){return d(),e("div",null,[...t[0]||(t[0]=[r('<h1 id="_22-スマレジ連携の全設定-完全ガイド" tabindex="-1">22. スマレジ連携の全設定（完全ガイド） <a class="header-anchor" href="#_22-スマレジ連携の全設定-完全ガイド" aria-label="Permalink to &quot;22. スマレジ連携の全設定（完全ガイド）&quot;">​</a></h1><p>POSLAは株式会社スマレジが提供するクラウドPOS「スマレジ」とOAuth認証で連携できます。本章ではテナント側でやること・POSLA運営側でやることを、どちらも完全な手順で記載します。</p><hr><h2 id="_22-1-連携の概要" tabindex="-1">22.1 連携の概要 <a class="header-anchor" href="#_22-1-連携の概要" aria-label="Permalink to &quot;22.1 連携の概要&quot;">​</a></h2><h3 id="何ができるのか" tabindex="-1">何ができるのか <a class="header-anchor" href="#何ができるのか" aria-label="Permalink to &quot;何ができるのか&quot;">​</a></h3><table tabindex="0"><thead><tr><th>機能</th><th>説明</th></tr></thead><tbody><tr><td>店舗マッピング</td><td>POSLAの店舗とスマレジの店舗を紐付ける</td></tr><tr><td>商品インポート</td><td>スマレジに登録済みの商品をPOSLAメニューとしてインポート</td></tr><tr><td>商品マッピング</td><td>POSLAのメニューとスマレジの商品を紐付け</td></tr><tr><td>売上連携</td><td>将来予定：POSLAの売上データをスマレジに同期</td></tr></tbody></table><h3 id="前提条件" tabindex="-1">前提条件 <a class="header-anchor" href="#前提条件" aria-label="Permalink to &quot;前提条件&quot;">​</a></h3><ul><li>テナントがスマレジの契約を持っていること</li><li>スマレジ側に店舗と商品マスタが登録済みであること</li><li>POSLA運営がスマレジ開発者コンソールでOAuthクライアントを登録済みであること</li></ul><hr><h2 id="_22-2-テナント側の接続手順" tabindex="-1">22.2 テナント側の接続手順 <a class="header-anchor" href="#_22-2-テナント側の接続手順" aria-label="Permalink to &quot;22.2 テナント側の接続手順&quot;">​</a></h2><h3 id="_22-2-1-スマレジアカウントの準備" tabindex="-1">22.2.1 スマレジアカウントの準備 <a class="header-anchor" href="#_22-2-1-スマレジアカウントの準備" aria-label="Permalink to &quot;22.2.1 スマレジアカウントの準備&quot;">​</a></h3><ol><li>スマレジにログイン（管理者権限が必要）</li><li>契約ID（<code>contract_id</code>）を控える</li><li>スマレジに対象店舗と商品が登録されていることを確認</li></ol><h3 id="_22-2-2-poslaでの接続" tabindex="-1">22.2.2 POSLAでの接続 <a class="header-anchor" href="#_22-2-2-poslaでの接続" aria-label="Permalink to &quot;22.2.2 POSLAでの接続&quot;">​</a></h3><ol><li>POSLAのオーナーダッシュボードにログイン</li><li>「外部POS連携」タブを開く</li><li>「スマレジと接続」ボタンをクリック</li><li>スマレジのOAuth認証画面にリダイレクト</li><li>スマレジアカウントでログインし、POSLAからのアクセスを許可</li><li>POSLAにリダイレクトされ、接続完了</li><li>「接続状態」が「接続済み」に変わります</li></ol><h3 id="_22-2-3-店舗マッピング" tabindex="-1">22.2.3 店舗マッピング <a class="header-anchor" href="#_22-2-3-店舗マッピング" aria-label="Permalink to &quot;22.2.3 店舗マッピング&quot;">​</a></h3><ol><li>「外部POS連携」タブの「店舗マッピング」セクション</li><li>POSLAの各店舗について、対応するスマレジ店舗をドロップダウンで選択</li><li>「保存」をクリック</li></ol><table tabindex="0"><thead><tr><th>POSLA店舗</th><th>スマレジ店舗</th></tr></thead><tbody><tr><td>本店</td><td>→ 選択</td></tr><tr><td>支店A</td><td>→ 選択</td></tr></tbody></table><h3 id="_22-2-4-商品インポート" tabindex="-1">22.2.4 商品インポート <a class="header-anchor" href="#_22-2-4-商品インポート" aria-label="Permalink to &quot;22.2.4 商品インポート&quot;">​</a></h3><ol><li>店舗マッピング完了後、「商品インポート」ボタンをクリック</li><li>スマレジから商品一覧を取得</li><li>インポート対象の商品にチェック</li><li>「インポート開始」をクリック</li><li>以下の情報がPOSLAメニューとして登録されます： <ul><li>商品名</li><li>価格</li><li>カテゴリ</li><li>バーコード（あれば）</li></ul></li></ol><div class="warning custom-block"><p class="custom-block-title">非破壊インポート</p><p>既存のPOSLAメニューは<strong>維持</strong>されます。スマレジからの商品は新規追加または既存メニューへのマッピングとして登録されます。</p></div><h3 id="_22-2-5-商品マッピング" tabindex="-1">22.2.5 商品マッピング <a class="header-anchor" href="#_22-2-5-商品マッピング" aria-label="Permalink to &quot;22.2.5 商品マッピング&quot;">​</a></h3><p>既存のPOSLAメニューとスマレジ商品を手動で紐付ける場合：</p><ol><li>「商品マッピング」セクション</li><li>POSLAメニューの各項目について、対応するスマレジ商品を選択</li><li>「保存」をクリック</li></ol><h3 id="_22-2-6-接続解除" tabindex="-1">22.2.6 接続解除 <a class="header-anchor" href="#_22-2-6-接続解除" aria-label="Permalink to &quot;22.2.6 接続解除&quot;">​</a></h3><ol><li>「外部POS連携」タブ</li><li>「接続解除」ボタンをクリック</li><li>確認ダイアログで「はい」をクリック</li><li>トークンが削除され、スマレジとの連携が解除されます</li></ol><hr><h2 id="_22-3-posla運営側の設定手順" tabindex="-1">22.3 POSLA運営側の設定手順 <a class="header-anchor" href="#_22-3-posla運営側の設定手順" aria-label="Permalink to &quot;22.3 POSLA運営側の設定手順&quot;">​</a></h2><h3 id="_22-3-1-スマレジ開発者コンソールでアプリ登録" tabindex="-1">22.3.1 スマレジ開発者コンソールでアプリ登録 <a class="header-anchor" href="#_22-3-1-スマレジ開発者コンソールでアプリ登録" aria-label="Permalink to &quot;22.3.1 スマレジ開発者コンソールでアプリ登録&quot;">​</a></h3><ol><li><a href="https://developers.smaregi.dev/" target="_blank" rel="noreferrer">スマレジ開発者コンソール</a> にログイン</li><li>「アプリ登録」から新規アプリを作成</li><li>以下を入力： <ul><li>アプリ名：POSLA</li><li>リダイレクトURI：<code>https://eat.posla.jp/api/smaregi/callback.php</code></li><li>スコープ：<code>pos.products:read</code>, <code>pos.stores:read</code>, <code>pos.transactions:read</code> など</li></ul></li><li>クライアントID（<code>client_id</code>）とクライアントシークレット（<code>client_secret</code>）を取得</li></ol><h3 id="_22-3-2-posla管理画面への登録" tabindex="-1">22.3.2 POSLA管理画面への登録 <a class="header-anchor" href="#_22-3-2-posla管理画面への登録" aria-label="Permalink to &quot;22.3.2 POSLA管理画面への登録&quot;">​</a></h3><p>POSLA管理画面の「API設定」タブで以下を入力：</p><table tabindex="0"><thead><tr><th>キー名</th><th>値</th></tr></thead><tbody><tr><td>smaregi_client_id</td><td>スマレジのクライアントID</td></tr><tr><td>smaregi_client_secret</td><td>スマレジのクライアントシークレット</td></tr></tbody></table><h3 id="_22-3-3-oauthトークン管理" tabindex="-1">22.3.3 OAuthトークン管理 <a class="header-anchor" href="#_22-3-3-oauthトークン管理" aria-label="Permalink to &quot;22.3.3 OAuthトークン管理&quot;">​</a></h3><p>POSLAはテナントごとに以下のトークンを保持します。</p><table tabindex="0"><thead><tr><th>フィールド</th><th>説明</th></tr></thead><tbody><tr><td>smaregi_contract_id</td><td>スマレジの契約ID</td></tr><tr><td>smaregi_access_token</td><td>アクセストークン</td></tr><tr><td>smaregi_refresh_token</td><td>リフレッシュトークン</td></tr><tr><td>smaregi_token_expires_at</td><td>トークン有効期限</td></tr><tr><td>smaregi_connected_at</td><td>接続日時</td></tr></tbody></table><p><strong>トークンリフレッシュ：</strong></p><ul><li>有効期限の<strong>5分前</strong>に自動リフレッシュ</li><li>API呼び出し時に期限切れが検知された場合も自動リフレッシュ</li><li>リフレッシュ失敗時は<code>smaregi_access_token</code>をNULLに戻し、テナントに再接続を促す</li></ul><h3 id="_22-3-4-マッピングテーブル" tabindex="-1">22.3.4 マッピングテーブル <a class="header-anchor" href="#_22-3-4-マッピングテーブル" aria-label="Permalink to &quot;22.3.4 マッピングテーブル&quot;">​</a></h3><table tabindex="0"><thead><tr><th>テーブル</th><th>説明</th></tr></thead><tbody><tr><td>smaregi_store_mapping</td><td>POSLA店舗 ↔ スマレジ店舗</td></tr><tr><td>smaregi_product_mapping</td><td>POSLAメニュー ↔ スマレジ商品</td></tr></tbody></table><p><strong>smaregi_store_mapping：</strong></p><table tabindex="0"><thead><tr><th>フィールド</th><th>説明</th></tr></thead><tbody><tr><td>tenant_id</td><td>テナントID</td></tr><tr><td>posla_store_id</td><td>POSLA店舗ID</td></tr><tr><td>smaregi_store_id</td><td>スマレジ店舗ID</td></tr><tr><td>created_at</td><td>作成日時</td></tr><tr><td>updated_at</td><td>更新日時</td></tr></tbody></table><p><strong>smaregi_product_mapping：</strong></p><table tabindex="0"><thead><tr><th>フィールド</th><th>説明</th></tr></thead><tbody><tr><td>tenant_id</td><td>テナントID</td></tr><tr><td>posla_menu_id</td><td>POSLAメニューID</td></tr><tr><td>smaregi_product_id</td><td>スマレジ商品ID</td></tr><tr><td>smaregi_price_division_id</td><td>価格区分ID（店舗別価格）</td></tr><tr><td>created_at</td><td>作成日時</td></tr></tbody></table><h3 id="_22-3-5-apiエンドポイント" tabindex="-1">22.3.5 APIエンドポイント <a class="header-anchor" href="#_22-3-5-apiエンドポイント" aria-label="Permalink to &quot;22.3.5 APIエンドポイント&quot;">​</a></h3><p>POSLA側のスマレジ連携APIは <code>/api/smaregi/</code> 配下に実装されています。</p><table tabindex="0"><thead><tr><th>エンドポイント</th><th>説明</th></tr></thead><tbody><tr><td><code>/api/smaregi/connect.php</code></td><td>OAuth開始。スマレジへリダイレクト</td></tr><tr><td><code>/api/smaregi/callback.php</code></td><td>OAuth完了。トークン保存</td></tr><tr><td><code>/api/smaregi/status.php</code></td><td>接続状態取得</td></tr><tr><td><code>/api/smaregi/stores.php</code></td><td>スマレジ店舗一覧取得</td></tr><tr><td><code>/api/smaregi/products.php</code></td><td>スマレジ商品一覧取得</td></tr><tr><td><code>/api/smaregi/import.php</code></td><td>商品インポート実行</td></tr><tr><td><code>/api/smaregi/mappings.php</code></td><td>マッピング保存・取得</td></tr><tr><td><code>/api/smaregi/disconnect.php</code></td><td>接続解除</td></tr></tbody></table><hr><h2 id="_22-4-動作確認" tabindex="-1">22.4 動作確認 <a class="header-anchor" href="#_22-4-動作確認" aria-label="Permalink to &quot;22.4 動作確認&quot;">​</a></h2><h3 id="テナント接続テスト" tabindex="-1">テナント接続テスト <a class="header-anchor" href="#テナント接続テスト" aria-label="Permalink to &quot;テナント接続テスト&quot;">​</a></h3><ol><li>テストテナントでスマレジに接続</li><li>以下を確認： <ul><li>接続ボタンを押すとスマレジへリダイレクト</li><li>スマレジで認証後、POSLAに戻ってくる</li><li><code>smaregi_access_token</code>が保存される</li><li>「接続状態」が「接続済み」と表示される</li></ul></li></ol><h3 id="トークンリフレッシュテスト" tabindex="-1">トークンリフレッシュテスト <a class="header-anchor" href="#トークンリフレッシュテスト" aria-label="Permalink to &quot;トークンリフレッシュテスト&quot;">​</a></h3><ol><li><code>smaregi_token_expires_at</code>を手動で5分後に更新</li><li>APIを呼び出す</li><li>自動的にトークンがリフレッシュされることを確認</li><li>新しい<code>smaregi_token_expires_at</code>が保存されていることを確認</li></ol><h3 id="商品インポートテスト" tabindex="-1">商品インポートテスト <a class="header-anchor" href="#商品インポートテスト" aria-label="Permalink to &quot;商品インポートテスト&quot;">​</a></h3><ol><li>スマレジに10件程度の商品を登録</li><li>POSLAで商品インポートを実行</li><li>POSLAメニューに10件追加されていることを確認</li><li><code>smaregi_product_mapping</code>に10行のマッピングが作成されていることを確認</li></ol><hr><h2 id="_22-5-トラブルシューティング" tabindex="-1">22.5 トラブルシューティング <a class="header-anchor" href="#_22-5-トラブルシューティング" aria-label="Permalink to &quot;22.5 トラブルシューティング&quot;">​</a></h2><table tabindex="0"><thead><tr><th>問題</th><th>原因</th><th>対処</th></tr></thead><tbody><tr><td>OAuth接続時に「アプリが見つかりません」</td><td>POSLA管理画面の<code>smaregi_client_id</code>が未設定</td><td>POSLA管理画面で設定</td></tr><tr><td>接続後すぐに切断される</td><td>リダイレクトURIが不一致</td><td>スマレジ開発者コンソールでURIを確認</td></tr><tr><td>商品インポート時に「権限がありません」</td><td>OAuthスコープが不足</td><td>スマレジ開発者コンソールでスコープを追加し、再接続</td></tr><tr><td>トークンが失効する</td><td>リフレッシュ処理のエラー</td><td><code>error_log</code>を確認。手動で再接続</td></tr><tr><td>店舗マッピングが保存されない</td><td>POSLA店舗ID/スマレジ店舗IDの不一致</td><td>ブラウザ開発者ツールでネットワークエラーを確認</td></tr></tbody></table>',57)])])}const b=a(i,[["render",l]]);export{p as __pageData,b as default};
